import React from 'react';

export default function KonferansEkibi() {
  const teamMembers = [
    { id: 1, name: 'Üye 1', role: 'Başkan' },
    { id: 2, name: 'Üye 2', role: 'Başkan Yardımcısı' },
    { id: 3, name: 'Üye 3', role: 'Sekreter' },
    { id: 4, name: 'Üye 4', role: 'Muhasebeci' },
    { id: 5, name: 'Üye 5', role: 'Üye' },
    { id: 6, name: 'Üye 6', role: 'Üye' },
  ];

  return (
    <section className="py-5">
      <div className="container">
        <h1 className="text-center mb-5">Konferans Ekibi</h1>
        <div className="row">
          {teamMembers.map((member) => (
            <div className="col-md-4 mb-4" key={member.id}>
              <div className="card h-100">
                <img
                  src="https://via.placeholder.com/300x250"
                  className="card-img-top"
                  alt={member.name}
                />
                <div className="card-body text-center">
                  <h5 className="card-title">{member.name}</h5>
                  <p className="card-text text-muted">{member.role}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
